<?php  namespace App\Http\Controllers\Admin;  use App\Http\Controllers\Controller; use Spatie\Activitylog\Models\Activity; use Illuminate\Http\Request;  class AuditLogController extends Controller {     public function index(Request $request)     {         $query = Activity::with("causer")->latest();          if ($request->filled("causer_id")) {             $query->where("causer_id", $request->causer_id);         }          if ($request->filled("log_name")) {             $query->where("log_name", $request->log_name);         }          $logs = $query->paginate(30);          return view("admin.audit-logs.index", compact("logs"));     }      public function show(string $id)     {         $log = Activity::findOrFail($id);         return view("admin.audit-logs.show", compact("log"));     }      public function create() { return redirect()->route("admin.audit-logs.index"); }     public function store(Request $r) { return redirect()->route("admin.audit-logs.index"); }     public function edit(string $id) { return redirect()->route("admin.audit-logs.index"); }     public function update(Request $r, string $id) { return redirect()->route("admin.audit-logs.index"); }     public function destroy(string $id) { return redirect()->route("admin.audit-logs.index"); } }